import React, { useCallback, useEffect, useState } from 'react';
import { useAppDispatch } from '../../store/hooks';
import { Button, Modal, dispatchAppToast } from '@linm-soft/common-components';
import { masterService } from '../../services/master/masterService';
import type { SharedCatalogChangeRequestDto, SharedCatalogUsageDto } from '../../services/master/models';
import { formatDateTimeLocal } from '../../utils/formatters';
import styles from '../../styles/erpPage.module.css';

export interface SharedCatalogApprovalDrawerProps {
  testIdPrefix: string;
  catalogKind: string;
  isOpen: boolean;
  onClose: () => void;
  onReviewed?: () => void;
}

const actionLabel = (action: string) => {
  switch (action) {
    case 'Create':
      return 'Thêm dùng chung';
    case 'Update':
      return 'Sửa';
    case 'Delete':
      return 'Xóa';
    default:
      return action;
  }
};

/** Approver drawer — usage + change-request queue (GAP-P1-SHARED-03). */
export const SharedCatalogApprovalDrawer: React.FC<SharedCatalogApprovalDrawerProps> = ({
  testIdPrefix,
  catalogKind,
  isOpen,
  onClose,
  onReviewed,
}) => {
  const dispatch = useAppDispatch();
  const [loading, setLoading] = useState(false);
  const [busyId, setBusyId] = useState<string | null>(null);
  const [usageRows, setUsageRows] = useState<SharedCatalogUsageDto[]>([]);
  const [changeRows, setChangeRows] = useState<SharedCatalogChangeRequestDto[]>([]);

  const loadQueue = useCallback(async () => {
    setLoading(true);
    try {
      const [usage, changes] = await Promise.all([
        masterService.listSharedCatalogUsageRequests(catalogKind, 'Pending'),
        masterService.listSharedCatalogChangeRequests(catalogKind, 'Pending'),
      ]);
      setUsageRows(usage);
      setChangeRows(changes);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Không tải được hàng đợi duyệt',
        type: 'error',
      });
    } finally {
      setLoading(false);
    }
  }, [catalogKind]);

  useEffect(() => {
    if (!isOpen) return;
    const t = window.setTimeout(() => void loadQueue(), 0);
    return () => window.clearTimeout(t);
  }, [isOpen, loadQueue]);

  const reviewUsage = async (id: string, approve: boolean) => {
    setBusyId(`usage-${id}`);
    try {
      if (approve) await masterService.approveSharedCatalogUsage(id);
      else await masterService.rejectSharedCatalogUsage(id);
      dispatchAppToast(dispatch, { message: approve ? 'Đã duyệt yêu cầu dùng chung' : 'Đã từ chối yêu cầu', type: 'success' });
      await loadQueue();
      onReviewed?.();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Duyệt thất bại', type: 'error' });
    } finally {
      setBusyId(null);
    }
  };

  const reviewChange = async (id: string, approve: boolean) => {
    setBusyId(`change-${id}`);
    try {
      if (approve) await masterService.approveSharedCatalogChange(id);
      else await masterService.rejectSharedCatalogChange(id);
      dispatchAppToast(dispatch, { message: approve ? 'Đã duyệt đề xuất' : 'Đã từ chối đề xuất', type: 'success' });
      await loadQueue();
      onReviewed?.();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Duyệt thất bại', type: 'error' });
    } finally {
      setBusyId(null);
    }
  };

  const empty = !loading && usageRows.length === 0 && changeRows.length === 0;

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Chờ duyệt danh mục dùng chung"
      data-testid={`${testIdPrefix}-approval-drawer`}
    >
      <div className={styles.sharedApprovalBody} data-testid={`${testIdPrefix}-approval-body`}>
        {loading && (
          <p className={styles.sharedCatalogHint} data-testid={`${testIdPrefix}-approval-loading`}>
            <i className="fas fa-spinner fa-spin" /> Đang tải…
          </p>
        )}

        {!loading && (
          <>
            <section className={styles.sharedApprovalSection}>
              <h3 className={styles.sharedApprovalHeading}>
                Yêu cầu sử dụng chung ({usageRows.length})
              </h3>
              {usageRows.length === 0 ? (
                <p className={styles.sharedCatalogHint}>Không có yêu cầu chờ duyệt.</p>
              ) : (
                <div className={styles.tableWrap}>
                  <table className={styles.table} data-testid={`${testIdPrefix}-usage-queue-table`}>
                    <thead>
                      <tr>
                        <th>Đơn vị</th>
                        <th>Người gửi</th>
                        <th>Thời gian</th>
                        <th />
                      </tr>
                    </thead>
                    <tbody>
                      {usageRows.map(row => (
                        <tr key={row.id} data-testid={`${testIdPrefix}-usage-row-${row.id}`}>
                          <td>{row.companyCode ?? row.companyId ?? '—'}</td>
                          <td>{row.requestedBy ?? '—'}</td>
                          <td>{row.requestedAt ? formatDateTimeLocal(row.requestedAt) : '—'}</td>
                          <td className={styles.rowActions}>
                            <Button
                              variant="primary"
                              size="sm"
                              disabled={busyId != null}
                              data-testid={`${testIdPrefix}-usage-approve-${row.id}`}
                              onClick={() => void reviewUsage(row.id, true)}
                            >
                              Duyệt
                            </Button>
                            <Button
                              variant="secondary"
                              size="sm"
                              disabled={busyId != null}
                              data-testid={`${testIdPrefix}-usage-reject-${row.id}`}
                              onClick={() => void reviewUsage(row.id, false)}
                            >
                              Từ chối
                            </Button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </section>

            <section className={styles.sharedApprovalSection}>
              <h3 className={styles.sharedApprovalHeading}>
                Đề xuất sửa shared ({changeRows.length})
              </h3>
              {changeRows.length === 0 ? (
                <p className={styles.sharedCatalogHint}>Không có đề xuất chờ duyệt.</p>
              ) : (
                <div className={styles.tableWrap}>
                  <table className={styles.table} data-testid={`${testIdPrefix}-change-queue-table`}>
                    <thead>
                      <tr>
                        <th>Đơn vị</th>
                        <th>Thao tác</th>
                        <th>Mã</th>
                        <th>Nội dung</th>
                        <th />
                      </tr>
                    </thead>
                    <tbody>
                      {changeRows.map(row => (
                        <tr key={row.id} data-testid={`${testIdPrefix}-change-row-${row.id}`}>
                          <td>{row.companyCode ?? row.companyId ?? '—'}</td>
                          <td>{actionLabel(row.action)}</td>
                          <td>{row.entityKey}</td>
                          <td className={styles.sharedApprovalPayload}>
                            {row.payloadJson ?? '—'}
                          </td>
                          <td className={styles.rowActions}>
                            <Button
                              variant="primary"
                              size="sm"
                              disabled={busyId != null}
                              data-testid={`${testIdPrefix}-change-approve-${row.id}`}
                              onClick={() => void reviewChange(row.id, true)}
                            >
                              Duyệt
                            </Button>
                            <Button
                              variant="secondary"
                              size="sm"
                              disabled={busyId != null}
                              data-testid={`${testIdPrefix}-change-reject-${row.id}`}
                              onClick={() => void reviewChange(row.id, false)}
                            >
                              Từ chối
                            </Button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </section>

            {empty && (
              <p className={styles.sharedCatalogHint} data-testid={`${testIdPrefix}-approval-empty`}>
                Hàng đợi trống.
              </p>
            )}
          </>
        )}
      </div>
      <div className={styles.modalFooterBar}>
        <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-approval-close`}>
          Đóng
        </Button>
      </div>
    </Modal>
  );
};
