import type { CatalogUiField, CatalogUiSchema } from '../../../types/catalogUiSchema';
import type { SharedCatalogProposalFieldDef } from '../sharedCatalogProposalFieldRegistry';

export function listVisibleFields(schema: CatalogUiSchema | null): CatalogUiField[] {
  if (!schema) return [];
  return schema.fields
    .filter(f => f.list?.visible)
    .sort((a, b) => (a.list?.order ?? 0) - (b.list?.order ?? 0));
}

export function proposalEditableFields(schema: CatalogUiSchema | null): CatalogUiField[] {
  if (!schema) return [];
  return schema.fields
    .filter(f => f.proposal?.editable)
    .sort((a, b) => (a.proposal?.order ?? 0) - (b.proposal?.order ?? 0));
}

export function toProposalFieldDefs(fields: CatalogUiField[]): SharedCatalogProposalFieldDef[] {
  return fields.map(f => ({
    key: f.key,
    label: f.label,
    type: f.control === 'BOOL' ? 'boolean' : 'text',
  }));
}

export function getRowFieldValue(row: Record<string, unknown>, key: string): unknown {
  return row[key];
}
