import React from 'react';
import type { CodeReplacePending } from '../../services/master/codeReplace';
import { useCatalogCodeReplaceForCode } from './CatalogCodeReplaceContext';
import styles from '../../styles/erpPage.module.css';

const STATUS_LABEL: Record<string, string> = {
  Draft: 'Chờ áp dụng',
  Running: 'Đang đổi mã',
  Failed: 'Đổi mã lỗi',
  Completed: 'Đã đổi mã',
};

type CatalogCodeReplaceListBadgeProps = {
  testIdPrefix: string;
  code: string;
  pending?: CodeReplacePending;
};

export function CatalogCodeReplaceListBadge({
  testIdPrefix,
  code,
  pending,
}: CatalogCodeReplaceListBadgeProps): React.ReactElement | null {
  if (!pending) return null;
  const label = STATUS_LABEL[pending.status] ?? pending.status;
  const title = pending.errorMessage
    ? `${pending.oldCode} → ${pending.newCode}: ${pending.errorMessage}`
    : `${pending.oldCode} → ${pending.newCode}`;
  return (
    <span
      className={styles.catalogCodeReplaceBadge}
      title={title}
      data-testid={`${testIdPrefix}-code-replace-${code}`}
    >
      {label}
    </span>
  );
}

export function CatalogCodeWithReplaceBadge({
  testIdPrefix,
  code,
  pending,
}: CatalogCodeReplaceListBadgeProps): React.ReactElement {
  return (
    <span className={styles.catalogCodeWithBadge}>
      <code>{code}</code>
      <CatalogCodeReplaceListBadge testIdPrefix={testIdPrefix} code={code} pending={pending} />
    </span>
  );
}

/** Manual list grid `<td>` — dùng trong CatalogCodeReplaceProvider. */
export function CatalogListCodeCell({
  testIdPrefix,
  code,
}: {
  testIdPrefix: string;
  code: string;
}): React.ReactElement {
  const pending = useCatalogCodeReplaceForCode(code);
  return (
    <td>
      {pending ? (
        <CatalogCodeWithReplaceBadge testIdPrefix={testIdPrefix} code={code} pending={pending} />
      ) : (
        <code>{code}</code>
      )}
    </td>
  );
}
