import React, { useState } from 'react';
import { Button, useDeviceContentSize } from '@linm-soft/common-components';
import { AnchoredDropdown } from './AnchoredDropdown';
import styles from '../../styles/erpPage.module.css';

export interface CatalogListToolbarProps {
  testIdPrefix: string;
  canAdd?: boolean;
  canEdit?: boolean;
  canHistory?: boolean;
  canRename?: boolean;
  canDelete?: boolean;
  selectedCount?: number;
  onAdd?: () => void;
  onEdit?: () => void;
  onHistory?: () => void;
  onRefresh?: () => void;
  onRename?: () => void;
  onDelete?: () => void;
  sharedActions?: React.ReactNode;
  extraLeftActions?: React.ReactNode;
}

export const CatalogListToolbar: React.FC<CatalogListToolbarProps> = ({
  testIdPrefix,
  canAdd = true,
  canEdit = false,
  canHistory = false,
  canRename = false,
  canDelete = false,
  selectedCount = 0,
  onAdd,
  onEdit,
  onHistory,
  onRefresh,
  onRename,
  onDelete,
  sharedActions,
  extraLeftActions,
}) => {
  const { isSmall } = useDeviceContentSize();
  const [moreOpen, setMoreOpen] = useState(false);
  const [actionsOpen, setActionsOpen] = useState(false);

  const refreshBtn = (
    <Button
      variant="secondary"
      size="sm"
      data-testid={`${testIdPrefix}-toolbar-refresh-btn`}
      onClick={onRefresh}
    >
      <i className="fas fa-sync-alt" /> Làm mới
    </Button>
  );

  const historyBtn = (
    <Button
      variant="secondary"
      size="sm"
      disabled={!canHistory}
      data-testid={`${testIdPrefix}-toolbar-history-btn`}
      onClick={onHistory}
    >
      <i className="fas fa-history" /> Lịch sử
    </Button>
  );

  const renameBtn = (
    <Button
      variant="secondary"
      size="sm"
      disabled={!canRename}
      data-testid={`${testIdPrefix}-rename-code-btn`}
      onClick={onRename}
    >
      <i className="fas fa-exchange-alt" /> Đổi mã
    </Button>
  );

  const deleteBtn = (
    <Button
      variant="secondary"
      size="sm"
      disabled={!canDelete || selectedCount === 0}
      data-testid={`${testIdPrefix}-batch-delete-btn`}
      onClick={onDelete}
    >
      <i className="fas fa-trash" /> Xóa
      {selectedCount > 0 ? ` (${selectedCount})` : ''}
    </Button>
  );

  const editBtn = (
    <Button
      variant="secondary"
      size="sm"
      disabled={!canEdit}
      data-testid={`${testIdPrefix}-toolbar-edit-btn`}
      onClick={onEdit}
    >
      <i className="fas fa-edit" /> Sửa
    </Button>
  );

  const addBtn = canAdd ? (
    <Button
      variant="primary"
      size="sm"
      data-testid={`${testIdPrefix}-toolbar-add-btn`}
      onClick={onAdd}
    >
      <i className="fas fa-plus" /> Thêm mới
    </Button>
  ) : null;

  const hasMore = Boolean(extraLeftActions || sharedActions);
  const showActionsDropdown = true;

  if (isSmall) {
    return (
      <div className={styles.catalogToolbarSticky} data-testid={`${testIdPrefix}-catalog-toolbar`}>
        <div className={styles.catalogToolbarLine1}>
          <div className={styles.catalogToolbarLeft}>
            {refreshBtn}
            {historyBtn}
            {hasMore ? (
              <AnchoredDropdown
                isOpen={moreOpen}
                onClose={() => setMoreOpen(false)}
                dropdownTestId={`${testIdPrefix}-toolbar-more-dropdown`}
                width={280}
                anchor={(
                  <Button
                    variant="secondary"
                    size="sm"
                    aria-label="Thêm thao tác"
                    data-testid={`${testIdPrefix}-toolbar-more-btn`}
                    onClick={() => setMoreOpen(v => !v)}
                  >
                    <i className="fas fa-ellipsis-h" />
                  </Button>
                )}
              >
                <div className={styles.anchoredDropdownBody}>
                  {extraLeftActions}
                  {sharedActions}
                </div>
              </AnchoredDropdown>
            ) : null}
          </div>
        </div>
        <div className={styles.catalogToolbarLine2}>
          <div className={styles.catalogToolbarLine2Buttons}>
            {showActionsDropdown ? (
              <AnchoredDropdown
                isOpen={actionsOpen}
                onClose={() => setActionsOpen(false)}
                dropdownTestId={`${testIdPrefix}-toolbar-actions-dropdown`}
                width="anchor"
                anchor={(
                  <Button
                    variant="secondary"
                    size="sm"
                    className={styles.catalogToolbarActionsDropdown}
                    data-testid={`${testIdPrefix}-toolbar-actions-btn`}
                    onClick={() => setActionsOpen(v => !v)}
                  >
                    Thao tác <i className="fas fa-chevron-down" />
                  </Button>
                )}
              >
                <div className={styles.anchoredDropdownBody}>
                  {deleteBtn}
                  {renameBtn}
                </div>
              </AnchoredDropdown>
            ) : null}
            {editBtn}
            {addBtn}
          </div>
        </div>
      </div>
    );
  }

  const leftActions = (
    <>
      {refreshBtn}
      {historyBtn}
      {extraLeftActions}
      {sharedActions}
    </>
  );

  const rightActions = (
    <>
      {renameBtn}
      {editBtn}
      {deleteBtn}
      {addBtn}
    </>
  );

  return (
    <div className={styles.catalogToolbarSticky} data-testid={`${testIdPrefix}-catalog-toolbar`}>
      <div className={styles.catalogToolbarLine1}>
        <div className={styles.catalogToolbarLeft}>{leftActions}</div>
        <div className={styles.catalogToolbarRight}>{rightActions}</div>
      </div>
    </div>
  );
};
